              <th className="text-center py-1">Predicted</th>
              <th className="text-center py-1">Actual Win%</th>
              <th className="text-center py-1">Trades</th>
              <th className="text-center py-1">Calibration</th>
            </tr>
          </thead>
          <tbody>
            {brierStats.calibrationBuckets.map(b => {
              const diff = Math.abs(b.actual - b.predicted)
              const calibColor = diff < 0.05 ? 'text-emerald-400' : diff < 0.15 ? 'text-yellow-400' : 'text-red-400'
              return (
                <tr key={b.pwinBucket} className="border-t border-slate-700/50">
                  <td className="py-2 font-mono">{b.pwinBucket}</td>
                  <td className="py-2 text-center">{(b.predicted * 100).toFixed(0)}%</td>
                  <td className={`py-2 text-center font-mono ${calibColor}`}>{(b.actual * 100).toFixed(1)}%</td>
                  <td className="py-2 text-center text-slate-400">{b.count}</td>
                  <td className={`py-2 text-center ${calibColor}`}>
                    {diff < 0.05 ? '\u2713 Good' : diff < 0.15 ? '~ OK' : '\u2717 Off'}
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>
    )}
  </div>
)}

